import{_ as r,c as s,o,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.62: Webfetch Returns Images","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.62.md","filePath":"en/changelog/v1.1.62.md","lastUpdated":1772014034000}'),n={name:"en/changelog/v1.1.62.md"};function i(l,a,h,d,c,p){return o(),s("div",null,[...a[0]||(a[0]=[t('<h1 id="v1-1-62-webfetch-returns-images" tabindex="-1">v1.1.62: Webfetch Returns Images <a class="header-anchor" href="#v1-1-62-webfetch-returns-images" aria-label="Permalink to “v1.1.62: Webfetch Returns Images”">​</a></h1><p><strong>Release Date</strong>: February 12, 2026</p><hr><h2 id="one-sentence-summary" tabindex="-1">One-Sentence Summary <a class="header-anchor" href="#one-sentence-summary" aria-label="Permalink to “One-Sentence Summary”">​</a></h2><p>This update lets <strong>Webfetch tool return image attachments</strong>, desktop project icons more stable, paste preserves undo history.</p><hr><h2 id="new-feature-webfetch-returns-images" tabindex="-1">New Feature: Webfetch Returns Images <a class="header-anchor" href="#new-feature-webfetch-returns-images" aria-label="Permalink to “New Feature: Webfetch Returns Images”">​</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>When using Webfetch tool to fetch webpages, <strong>images in the webpage are also returned as attachments</strong>.</p><h3 id="what-are-the-benefits" tabindex="-1">What are the Benefits? <a class="header-anchor" href="#what-are-the-benefits" aria-label="Permalink to “What are the Benefits?”">​</a></h3><ul><li>AI can &quot;see&quot; images in webpages</li><li>Easier to analyze screenshots, charts</li><li>More complete information obtained</li></ul><hr><h2 id="new-feature-shell-hook-exposes-tool-parameters" tabindex="-1">New Feature: Shell Hook Exposes Tool Parameters <a class="header-anchor" href="#new-feature-shell-hook-exposes-tool-parameters" aria-label="Permalink to “New Feature: Shell Hook Exposes Tool Parameters”">​</a></h2><h3 id="what-s-updated-1" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-1" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>Shell Hook can now access <strong>tool parameters</strong>, plugins can more precisely control tool behavior.</p><hr><h2 id="improvement-desktop-project-icons" tabindex="-1">Improvement: Desktop Project Icons <a class="header-anchor" href="#improvement-desktop-project-icons" aria-label="Permalink to “Improvement: Desktop Project Icons”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>Project icons in desktop app would sometimes unexpectedly unmount, displaying abnormally.</p><h3 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to “Current Status”">​</a></h3><p>Project icons no longer unexpectedly unmount, display is more stable.</p><hr><h2 id="improvement-paste-preserves-undo-history" tabindex="-1">Improvement: Paste Preserves Undo History <a class="header-anchor" href="#improvement-paste-preserves-undo-history" aria-label="Permalink to “Improvement: Paste Preserves Undo History”">​</a></h2><h3 id="previous-issue-1" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-1" aria-label="Permalink to “Previous Issue”">​</a></h3><p>After pasting plain text in desktop app, undo history would be lost.</p><h3 id="current-status-1" tabindex="-1">Current Status <a class="header-anchor" href="#current-status-1" aria-label="Permalink to “Current Status”">​</a></h3><p>After pasting plain text <strong>undo history is preserved</strong>, can use Ctrl+Z normally.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Need to fetch webpage images</td><td>✅ Upgrade</td></tr><tr><td>Using desktop version</td><td>✅ Upgrade</td></tr><tr><td>Everything works fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',31),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full update list</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Webfetch tool returns image attachments</li><li>Expose tool parameters in Shell Hook</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Project icons no longer unexpectedly unmount</li><li>Preserve undo history when pasting plain text</li><li>Refactor SolidJS code structure</li><li>More defensive session context metric handling</li></ul><h3 id="community-contributions" tabindex="-1">Community Contributions <a class="header-anchor" href="#community-contributions" aria-label="Permalink to “Community Contributions”">​</a></h3><ul><li>@gitRasheed: Fix paste to preserve undo history</li><li>@dtfiedler: Fix StructuredOutputs format property in docs</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const b=r(n,[["render",i]]);export{m as __pageData,b as default};
